def range_summary(nums):
    if not nums:
        return ''
    result = []
    start, end = nums[0], nums[0]
    for num in nums:
        if num == start + 1:
            pass
        elif num > end + 1:
            if start != end:
                result.append(f'{start}-{end}')
            start = num
        else:
            result.append(str(num))
            start = num
    if start != end:
        result.append(f'{start}-{end}')
    return ', '.join(result)
